mapper.select:
select D.TAISHO_NENGETSU as taishoNengetsu , D.GYOSHU_CD as gyoshuCd , M.GYOSHU_MEI as gyoshuMei , D.TORIATSUKAIDAKA as toriatsukaidaka , D.TESURYO_RITSU as tesuryoRitsu , D.TESURYO as tesuryo , D.TORIATSUKAIDAKA_RUIKEI as toriatsukaidakaRuikei , D.TESURYO_RUIKEI as tesuryoRuikei , D.KUMIAIIN_TORIATSUKAIDAKA as kumiaiin_toriatsukaidaka , D.KUMIAIIN_TESURYO_RITSU as kumiaiin_tesuryoRitsu , D.KUMIAIIN_TESURYO as kumiaiin_tesuryo , D.KUMIAIIN_TORIATSUKAIDAKA_RUIKEI as kumiaiin_toriatsukaidakaRuikei , D.KUMIAIIN_TESURYO_RITSU_RUIKEI as kumiaiin_tesuryoRitsuRuikei , D.TORIATSUKAIDAKA_TESURYO_RUIKEI as toriatsukaidakaTesuryoRuikei from DAC321_HANBAI_KYOKEI_TESURYO_HAIBUN_KEISAN_DATA D inner join DAA_GYOSHU_MST M on D.GYOSHU_CD = M.GYOSHU_CD and #{kijunNengetsuMatsujitsu} between M.TEKIYO_KAISHIBI and M.TEKIYO_SHURYOBI where D.TAISHO_NENGETSU = #{kijunNengetsu}
and D.GYOSHU_CD = #{gyoshuCd}
and D.GYOSHU_CD in
#{item}
order by D.GYOSHU_CD asc , D.TAISHO_NENGETSU asc

with KEISAN_DATA as ( select D.TAISHO_NENGETSU , D.GYOSHU_CD , D.KOBAI_TORIATSUKAIDAKA , D.KOBAI_TESURYO_RITSU , D.KOBAI_TESURYO , D.KOBAI_TORIATSUKAIDAKA_RUIKEI , D.KOBAI_TESURYO_RITSU_RUIKEI , D.KOBAI_TESURYO_RUIKEI , D.KUMIAIIN_KOBAI_TORIATSUKAIDAKA , D.KUMIAIIN_KOBAI_TESURYO_RITSU , D.KUMIAIIN_KOBAI_TESURYO , D.KUMIAIIN_KOBAI_TORIATSUKAIDAKA_RUIKEI , D.KUMIAIIN_KOBAI_TESURYO_RITSU_RUIKEI , D.KUMIAIIN_KOBAI_TESURYO_RUIKEI , D.SEIKATSU_TORIATSUKAIDAKA , D.SEIKATSU_TESURYO_RITSU , D.SEIKATSU_TESURYO , D.SEIKATSU_TORIATSUKAIDAKA_RUIKEI , D.SEIKATSU_TESURYO_RITSU_RUIKEI , D.SEIKATSU_TESURYO_RUIKEI , D.NENRYO_TORIATSUKAIDAKA , D.NENRYO_TESURYO_RITSU , D.NENRYO_TESURYO , D.NENRYO_TORIATSUKAIDAKA_RUIKEI , D.NENRYO_TESURYO_RITSU_RUIKEI , D.NENRYO_TESURYO_RUIKEI , D.ZAIKOHIN_TORIATSUKAIDAKA , D.ZAIKOHIN_TESURYO_RITSU , D.ZAIKOHIN_TESURYO , D.ZAIKOHIN_TORIATSUKAIDAKA_RUIKEI , D.ZAIKOHIN_TESURYO_RITSU_RUIKEI , D.ZAIKOHIN_TESURYO_RITSU_RUIKEI from DAC322_KOBAI_TESURYO_HAIBUN_KEISAN_DATA D where D.TAISHO_NENGETSU = #{kijunNengetsu} ) select K.TAISHO_NENGETSU as taishoNengetsu , K.GYOSHU_CD as gyoshuCd , M.GYOSHU_MEI as gyoshuMei , K.KOBAI_TORIATSUKAIDAKA as kobaiToriatsukaidaka , K.KOBAI_TESURYO_RITSU as kobaiTesuryoRitsu , K.KOBAI_TESURYO as kobaiTesuryo , K.KOBAI_TORIATSUKAIDAKA_RUIKEI as kobaiToriatsukaidakaRuikei , K.KOBAI_TESURYO_RITSU_RUIKEI as kobaiTesuryoRitsuRuikei , K.KOBAI_TESURYO_RUIKEI as kobaiTesuryoRuikei , K.KUMIAIIN_KOBAI_TORIATSUKAIDAKA as kumiaiin_kobaiToriatsukaidaka , K.KUMIAIIN_KOBAI_TESURYO_RITSU as kumiaiin_kobaiTesuryoRitsu , K.KUMIAIIN_KOBAI_TESURYO as kumiaiin_kobaiTesuryo , K.KUMIAIIN_KOBAI_TORIATSUKAIDAKA_RUIKEI as kumiaiin_kobaiToriatsukaidakaRuikei , K.KUMIAIIN_KOBAI_TESURYO_RITSU_RUIKEI as kumiaiin_kobaiTesuryoRitsuRuikei , K.KUMIAIIN_KOBAI_TESURYO_RUIKEI as kumiaiin_kobaiTesuryoRuikei , K.SEIKATSU_TORIATSUKAIDAKA as seikatsumono_toriatsukaidaka , K.SEIKATSU_TESURYO_RITSU as seikatsumono_tesuryoRitsu , K.SEIKATSU_TESURYO as seikatsumono_tesuryo , K.SEIKATSU_TORIATSUKAIDAKA_RUIKEI as seikatsumono_toriatsukaidakaRuikei , K.SEIKATSU_TESURYO_RITSU_RUIKEI as seikatsumono_tesuryoRitsuRuikei , K.SEIKATSU_TESURYO_RUIKEI as seikatsumono_tesuryoRuikei , K.NENRYO_TORIATSUKAIDAKA as nenryo_toriatsukaidaka , K.NENRYO_TESURYO_RITSU as nenryo_tesuryoRitsu , K.NENRYO_TESURYO as nenryo_tesuryo , K.NENRYO_TORIATSUKAIDAKA_RUIKEI as nenryo_toriatsukaidakaRuikei , K.NENRYO_TESURYO_RITSU_RUIKEI as nenryo_tesuryoRitsuRuikei , K.NENRYO_TESURYO_RUIKEI as nenryo_tesuryoRuikei , K.ZAIKOHIN_TORIATSUKAIDAKA as zaikohin_toriatsukaidaka , K.ZAIKOHIN_TESURYO_RITSU as zaikohin_tesuryoRitsu , K.ZAIKOHIN_TESURYO as zaikohin_tesuryo , K.ZAIKOHIN_TORIATSUKAIDAKA_RUIKEI as zaikohin_toriatsukaidakaRuikei , K.ZAIKOHIN_TESURYO_RITSU_RUIKEI as zaikohin_tesuryoRitsuRuikei , K.ZAIKOHIN_TESURYO_RITSU_RUIKEI as zaikohinTesuryoRitsuRuikei from KEISAN_DATA K inner join DAA_GYOSHU_MST M on K.GYOSHU_CD = M.GYOSHU_CD and #{kijunNengetsuMatsujitsu} between M.TEKIYO_KAISHIBI and M.TEKIYO_SHURYOBI where 1 = 1
and K.GYOSHU_CD = #{gyoshuCd}
and K.GYOSHU_CD in
#{item}
order by K.GYOSHU_CD asc , K.TAISHO_NENGETSU asc
